1	import { createHash } from 'crypto';
2	import { NodeLessonContent } from '../models/NodeLessonContent.model';
3	import {
4	  ICanonicalRoadmapNode,
5	  ICanonicalNodeLesson,
6	  ICanonicalNodeSource,
7	  IRoadmapLessonSource
8	} from '../types/roadmap.types';
9	import { getNodeLessons } from '../utils/nodeLessons.util';
10	import { extractTopicText } from '../utils/roadmapChapter.util';
11	import { roadmapAIService } from './roadmap.ai.service';
12	
13	type SubjectShape = {
14	  title?: string;
15	  books?: Array<{ _id?: { toString(): string }; title?: string }>;
16	};
17	
18	function nodeKtpTopicId(node: ICanonicalRoadmapNode): string | null {
19	  const md = node.metadata as Record<string, unknown> | undefined;
20	  const id = md && typeof md.ktpTopicId === 'string' ? md.ktpTopicId : undefined;
21	  return id ?? null;
22	}
23	
24	function nodeSources(node: ICanonicalRoadmapNode): ICanonicalNodeSource[] {
25	  const md = node.metadata as Record<string, unknown> | undefined;
26	  const arr = md?.sources;
27	  return Array.isArray(arr) ? (arr as ICanonicalNodeSource[]) : [];
28	}
29	
30	function bookTitleOf(subject: SubjectShape, bookId: string): string | undefined {
31	  return subject.books?.find((b) => b._id?.toString() === bookId)?.title;
32	}
33	
34	/** Источники узла с метками и текстами (для AI-консолидации). */
35	function sourcesWithText(
36	  subject: unknown,
37	  sources: ICanonicalNodeSource[]
38	): Array<{ source: ICanonicalNodeSource; label: string; text: string }> {
39	  const sub = subject as SubjectShape;
40	  return sources
41	    .map((s) => {
42	      const bookTitle = bookTitleOf(sub, s.bookId) || 'Книга';
43	      const label = s.title ? `${bookTitle} · ${s.title}` : bookTitle;
44	      const text = extractTopicText(subject, s.bookId, s.chapterId, s.topicId) || s.title || '';
45	      return { source: s, label, text };
46	    })
47	    .filter((x) => x.text.trim());
48	}
49	
50	function computeSourceHash(items: Array<{ topicId: string; text: string }>): string {
51	  return createHash('sha256').update(JSON.stringify(items.map((i) => [i.topicId, i.text]))).digest('hex');
52	}
53	
54	function storedToLessons(row: { lessons?: ICanonicalNodeLesson[] }): ICanonicalNodeLesson[] {
55	  return [...(row.lessons ?? [])]
56	    .map((l) => ({
57	      lessonId: l.lessonId,
58	      title: l.title,
59	      order: l.order,
60	      content: l.content,
61	      contentFormat: l.contentFormat === 'html' ? ('html' as const) : ('markdown' as const),
62	      ...(l.summary ? { summary: l.summary } : {}),
63	      video: null
64	    }))
65	    .sort((a, b) => a.order - b.order);
66	}
67	
68	/** Описание источников узла для UI (книга/класс + тема), без текстов. */
69	export function describeNodeSources(subject: unknown, node: ICanonicalRoadmapNode): IRoadmapLessonSource[] {
70	  const sub = subject as SubjectShape;
71	  return nodeSources(node).map((s) => ({
72	    ...(bookTitleOf(sub, s.bookId) ? { bookTitle: bookTitleOf(sub, s.bookId) } : {}),
73	    ...(s.title ? { topicTitle: s.title } : {})
74	  }));
75	}
76	
77	/** Кэшированные уроки узла (без генерации). null — кэша нет или узел не из КТП. */
78	export async function getCachedNodeLessons(
79	  subjectId: string,
80	  node: ICanonicalRoadmapNode
81	): Promise<ICanonicalNodeLesson[] | null> {
82	  const ktpTopicId = nodeKtpTopicId(node);
83	  if (!ktpTopicId) return null;
84	  const row = await NodeLessonContent.findOne({ subjectId, ktpTopicId }).lean<{ lessons?: ICanonicalNodeLesson[] }>();
85	  if (!row || !row.lessons?.length) return null;
86	  return storedToLessons(row);
87	}
88	
89	/**
90	 * Уроки узла для показа: AI-консолидация из замапленных тем книг, кэш по sourceHash.
91	 * Промах/устаревший хэш → генерация и кэширование. Без OPENAI_API_KEY или при ошибке — сырой fallback.
92	 */
93	export async function resolveNodeLessons(
94	  subjectId: string,
95	  subject: unknown,
96	  node: ICanonicalRoadmapNode
97	): Promise<ICanonicalNodeLesson[]> {
98	  const ktpTopicId = nodeKtpTopicId(node);
99	  const sources = nodeSources(node);
100	  if (!ktpTopicId || sources.length === 0) return getNodeLessons(node);
101	
102	  const withText = sourcesWithText(subject, sources);
103	  if (withText.length === 0) return getNodeLessons(node);
104	
105	  const hash = computeSourceHash(withText.map((x) => ({ topicId: x.source.topicId, text: x.text })));
106	
107	  const row = await NodeLessonContent.findOne({ subjectId, ktpTopicId });
108	  if (row && row.lessons?.length && (row.generatedBy === 'manual' || row.sourceHash === hash)) {
109	    return storedToLessons(row);
110	  }
111	
112	  if (!process.env.OPENAI_API_KEY) {
113	    return getNodeLessons(node); // сырой fallback, не кэшируем
114	  }
115	
116	  let consolidated: Array<{ title: string; summary?: string; content: string }>;
117	  try {
118	    consolidated = await roadmapAIService.consolidateLessonContent({
119	      subjectTitle: (subject as SubjectShape).title || '',
120	      nodeTitle: node.title,
121	      sources: withText.map((x) => ({ label: x.label, text: x.text }))
122	    });
123	  } catch (e) {
124	    console.warn('[nodeLessonContent] consolidation failed, using raw sources', e);
125	    return getNodeLessons(node);
126	  }
127	
128	  const lessons: ICanonicalNodeLesson[] = consolidated.map((l, i) => ({
129	    lessonId: `${node.nodeId}::c${i}`,
130	    title: l.title || node.title,
131	    order: i,
132	    content: l.content,
133	    contentFormat: 'markdown',
134	    ...(l.summary ? { summary: l.summary } : {}),
135	    video: null
136	  }));
137	
138	  await NodeLessonContent.findOneAndUpdate(
139	    { subjectId, ktpTopicId },
140	    {
141	      $set: {
142	        subjectId,
143	        ktpTopicId,
144	        sourceHash: hash,
145	        generatedBy: 'ai',
146	        lessons: lessons.map((l) => ({
147	          lessonId: l.lessonId,
148	          title: l.title,
149	          order: l.order,
150	          content: l.content,
151	          contentFormat: l.contentFormat,
152	          ...(l.summary ? { summary: l.summary } : {})
153	        }))
154	      }
155	    },
156	    { upsert: true, new: true }
157	  ).catch((e) => console.warn('[nodeLessonContent] cache write failed', e));
158	
159	  return lessons;
160	}
161	
162	/** Упорядоченные lessonId узла (кэш, иначе сырой fallback) — для гейтинга/прогресса. */
163	export async function nodeLessonIds(subjectId: string, node: ICanonicalRoadmapNode): Promise<string[]> {
164	  const cached = await getCachedNodeLessons(subjectId, node);
165	  if (cached) return cached.map((l) => l.lessonId);
166	  return getNodeLessons(node).map((l) => l.lessonId);
167	}
