20	function stripHtmlToText(html: string): string {
21	  return html
22	    .replace(/<br\s*\/?>/gi, '\n')
23	    .replace(/<\/p>/gi, '\n')
24	    .replace(/<[^>]+>/g, ' ')
25	    .replace(/\s+/g, ' ')
26	    .trim();
27	}
28	
29	function normalizeLessonContent(raw: string, format: 'markdown' | 'html'): string {
30	  if (!raw.trim()) return '';
31	  return format === 'html' ? stripHtmlToText(raw) : raw;
32	}
