94	class RoadmapLessonService {
95	  private async resolveNode(subjectId: string, nodeId: string): Promise<ICanonicalRoadmapNode> {
96	    const bundle = await roadmapService.resolveCanonical(subjectId);
97	    const node = bundle.nodes.find((n) => n.nodeId === nodeId);
98	    if (!node) throw AppError.notFound('Roadmap node not found for this subject');
99	    return node;
100	  }
101	
102	  async getLesson(
103	    userId: string,
104	    subjectId: string,
105	    nodeId: string,
106	    lessonId?: string
107	  ): Promise<IRoadmapLessonResponse> {
108	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
109	
110	    const subject = await Subject.findById(subjectId).lean();
111	    if (!subject) throw AppError.notFound('Subject not found');
112	
113	    const node = await this.resolveNode(subjectId, nodeId);
114	    const lessons = await resolveNodeLessons(subjectId, subject, node);
115	    if (lessons.length === 0) throw AppError.notFound('Lesson not found for this node');
116	
117	    const progress = await roadmapService.getNodeProgress(userId, subjectId, nodeId);
118	    const readAtByLesson = new Map<string, Date | undefined>(
119	      (progress?.lessons ?? []).map((l) => [l.lessonId, l.readAt])
120	    );
121	    const completedSet = new Set([...readAtByLesson.keys()]);
122	    const listItems = lessonListItems(lessons, completedSet);
123	
124	    // Целевой урок: явный lessonId → он; иначе первый незавершённый; иначе первый.
125	    let targetIdx = lessonId ? lessons.findIndex((l) => l.lessonId === lessonId) : -1;
126	    if (targetIdx < 0 && !lessonId) {
127	      targetIdx = lessons.findIndex((l) => !completedSet.has(l.lessonId));
128	    }
129	    if (targetIdx < 0) targetIdx = 0;
130	    const target = lessons[targetIdx];
131	
132	    const contentNormalized = normalizeLessonContent(target.content, target.contentFormat);
133	
134	    let summary = target.summary?.trim() ?? '';
135	    if (!summary && contentNormalized.trim() && process.env.OPENAI_API_KEY) {
136	      summary = await roadmapAIService.generateLessonSummary({
137	        subjectTitle: subject.title,
138	        nodeTitle: target.title || node.title,
139	        lessonText: contentNormalized
140	      });
141	      if (summary) {
142	        await persistLessonSummary(subjectId, nodeId, target.lessonId, summary).catch((e) =>
143	          console.warn('[roadmapLesson] persist summary failed', e)
144	        );
145	      }
146	    }
147	
148	    const readAt = readAtByLesson.get(target.lessonId);
149	
150	    return {
151	      nodeId: node.nodeId,
152	      lessonId: target.lessonId,
153	      title: target.title || node.title,
154	      summary,
155	      content: contentNormalized,
156	      contentFormat: 'markdown',
157	      textFormat: 'markdown',
158	      video: target.video ?? null,
159	      readCompletedAt: readAt ? readAt.toISOString() : null,
160	      lessons: listItems,
161	      lessonsTotal: lessons.length,
162	      lessonIndex: targetIdx,
163	      nextLessonId: targetIdx < lessons.length - 1 ? lessons[targetIdx + 1].lessonId : null,
164	      prevLessonId: targetIdx > 0 ? lessons[targetIdx - 1].lessonId : null,
165	      locked: listItems[targetIdx]?.locked ?? false,
166	      sources: describeNodeSources(subject, node)
167	    };
168	  }
169	
170	  /**
171	   * Отметить урок прочитанным. Если lessonId не задан — завершаем первый незавершённый урок узла.
172	   * Последовательный гейтинг: нельзя завершить урок, пока не завершены предыдущие.
173	   */
174	  async markLessonRead(
175	    userId: string,
176	    subjectId: string,
177	    nodeId: string,
178	    lessonId?: string
179	  ): Promise<{ readCompletedAt: string; lessonId: string; allCompleted: boolean; nextLessonId: string | null }> {
180	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
181	
182	    const node = await this.resolveNode(subjectId, nodeId);
183	    const lessonIds = await nodeLessonIds(subjectId, node);
184	    if (lessonIds.length === 0) throw AppError.notFound('Lesson not found for this node');
185	
186	    let targetId = lessonId?.trim();
187	    if (!targetId) {
188	      const progress = await roadmapService.getNodeProgress(userId, subjectId, nodeId);
189	      const completed = new Set((progress?.lessons ?? []).map((l) => l.lessonId));
190	      targetId = lessonIds.find((id) => !completed.has(id)) ?? lessonIds[lessonIds.length - 1];
191	    }
192	
193	    // Валидация lessonId и последовательный гейтинг — в markLessonComplete.
194	    return roadmapService.markLessonComplete(userId, subjectId, nodeId, targetId);
195	  }
196	
197	  async postChatMessage(input: {
198	    userId: string;
199	    subjectId: string;
200	    nodeId: string;
201	    lessonId?: string;
202	    text: string;
203	    attachmentIds?: string[];
204	  }): Promise<{ reply: string }> {
205	    const { userId, subjectId, nodeId, text } = input;
206	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
207	    const trimmed = text?.trim() ?? '';
208	    if (!trimmed) throw AppError.badRequest('text is required');
209	
210	    const subject = await Subject.findById(subjectId).lean();
211	    if (!subject) throw AppError.notFound('Subject not found');
212	
213	    const node = await this.resolveNode(subjectId, nodeId);
214	    const lessons = await resolveNodeLessons(subjectId, subject, node);
215	    const lesson =
216	      (input.lessonId && lessons.find((l) => l.lessonId === input.lessonId)) || lessons[0];
217	    const lessonText = lesson ? normalizeLessonContent(lesson.content, lesson.contentFormat) : '';
218	
219	    const images: Array<{ mimeType: string; base64: string }> = [];
220	    const ids = (input.attachmentIds ?? []).filter(Boolean);
221	    for (const id of ids) {
222	      if (!mongoose.isValidObjectId(id)) throw AppError.badRequest(`Invalid attachment id: ${id}`);
223	      const att = await RoadmapChatAttachment.findOne({
224	        _id: id,
225	        userId,
226	        subjectId,
227	        nodeId
228	      }).lean();
229	      if (!att) throw AppError.badRequest(`Attachment not found: ${id}`);
230	      if (att.sizeBytes > ROADMAP_CHAT_MAX_BYTES) throw AppError.badRequest('Attachment too large');
231	
232	      const abs = path.join(process.cwd(), att.storageRelativePath);
233	      const buf = await fs.readFile(abs);
234	      images.push({
235	        mimeType: att.mimeType,
236	        base64: buf.toString('base64')
237	      });
238	    }
239	
240	    const reply = await roadmapAIService.chatLessonNode({
241	      subjectTitle: subject.title,
242	      nodeTitle: lesson?.title || node.title,
243	      nodeDescription: node.description?.trim(),
244	      lessonText,
245	      userMessage: trimmed,
246	      ...(images.length ? { images } : {})
247	    });
248	
249	    return { reply };
250	  }
251	
252	  async saveChatAttachment(input: {
253	    userId: string;
254	    subjectId: string;
255	    nodeId: string;
256	    attachmentId: mongoose.Types.ObjectId;
257	    absolutePath: string;
258	    mimeType: string;
259	    originalName: string;
260	    sizeBytes: number;
261	  }): Promise<{ attachmentId: string }> {
262	    const bundle = await roadmapService.resolveCanonical(input.subjectId);
263	    if (!bundle.nodes.some((n) => n.nodeId === input.nodeId)) {
264	      await fs.unlink(input.absolutePath).catch(() => undefined);
265	      throw AppError.notFound('Roadmap node not found for this subject');
266	    }
267	
268	    const rel = path.relative(process.cwd(), input.absolutePath);
269	    await RoadmapChatAttachment.create({
270	      _id: input.attachmentId,
271	      userId: input.userId,
272	      subjectId: input.subjectId,
273	      nodeId: input.nodeId,
274	      mimeType: input.mimeType,
275	      sizeBytes: input.sizeBytes,
276	      storageRelativePath: rel,
277	      originalName: input.originalName.slice(0, 512)
278	    });
279	    return { attachmentId: input.attachmentId.toString() };
280	  }
281	}
