9	function parseJsonObject(raw: string): Record<string, unknown> {
10	  const jsonStart = raw.indexOf('{');
11	  const jsonEnd = raw.lastIndexOf('}');
12	  if (jsonStart === -1 || jsonEnd === -1) {
13	    throw new Error('OpenAI response does not contain JSON');
14	  }
15	  return JSON.parse(raw.slice(jsonStart, jsonEnd + 1)) as Record<string, unknown>;
16	}
