18	export interface RoadmapPersonalAiInsights {
19	  coachSummary: string;
20	  nextStepExplanation?: string;
21	  /** Подсказки по узлам (nodeId → короткий текст) */
22	  nodeHints?: Record<string, string>;
23	}
