25	class RoadmapAIService {
26	  /**
27	   * Генерация canonical roadmap по тексту книги/главы (структура и prereq — решает модель).
28	   */
29	  async generateCanonicalFromBookContent(contentForAI: IContentForAI): Promise<ICanonicalRoadmapNode[]> {
30	    const apiKey = process.env.OPENAI_API_KEY;
31	    if (!apiKey) {
32	      throw AppError.badRequest('OPENAI_API_KEY is not set');
33	    }
34	
35	    let text = contentForAI.text;
36	    if (text.length > MAX_CHARS) {
37	      text = `${text.slice(0, MAX_CHARS)}\n\n[Текст обрезан для модели; при необходимости сгенерируйте roadmap по главам отдельно.]`;
38	    }
39	
