8	function parseVideo(raw: unknown): IRoadmapLessonVideo | null {
9	  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
10	  const o = raw as Record<string, unknown>;
11	  const url = typeof o.url === 'string' ? o.url.trim() : '';
12	  if (!url) return null;
13	  const durationSec =
14	    typeof o.durationSec === 'number' && Number.isFinite(o.durationSec) ? o.durationSec : undefined;
15	  const posterUrl = typeof o.posterUrl === 'string' && o.posterUrl.trim() ? o.posterUrl.trim() : undefined;
16	  return { url, ...(durationSec !== undefined ? { durationSec } : {}), ...(posterUrl ? { posterUrl } : {}) };
17	}
18	
19	function parseSource(raw: unknown): ICanonicalNodeSource | undefined {
20	  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return undefined;
21	  const o = raw as Record<string, unknown>;
22	  const bookId = typeof o.bookId === 'string' ? o.bookId : '';
23	  const chapterId = typeof o.chapterId === 'string' ? o.chapterId : '';
24	  const topicId = typeof o.topicId === 'string' ? o.topicId : '';
25	  if (!bookId || !chapterId || !topicId) return undefined;
26	  return { bookId, chapterId, topicId, ...(typeof o.title === 'string' ? { title: o.title } : {}) };
27	}
