29	function normalizeLesson(raw: unknown, node: ICanonicalRoadmapNode, index: number): ICanonicalNodeLesson | null {
30	  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
31	  const L = raw as Record<string, unknown>;
32	  const lessonId = typeof L.lessonId === 'string' && L.lessonId.trim() ? L.lessonId.trim() : `${node.nodeId}::l${index}`;
33	  const content = typeof L.content === 'string' ? L.content : '';
34	  return {
35	    lessonId,
36	    title: typeof L.title === 'string' && L.title.trim() ? L.title.trim() : node.title,
37	    order: typeof L.order === 'number' ? L.order : index,
38	    content,
39	    contentFormat: L.contentFormat === 'html' ? 'html' : 'markdown',
40	    ...(typeof L.summary === 'string' ? { summary: L.summary } : {}),
41	    video: parseVideo(L.video),
42	    ...(parseSource(L.source) ? { source: parseSource(L.source) } : {})
43	  };
44	}
