46	/**
47	 * Возвращает упорядоченный список уроков узла.
48	 * - КТП-узлы: metadata.lessons[] (несколько уроков из разных книг/классов).
49	 * - Старые/ручные узлы: одиночный metadata.lesson или node.description (fallback, 1 урок).
50	 */
51	export function getNodeLessons(node: ICanonicalRoadmapNode): ICanonicalNodeLesson[] {
52	  const md = (node.metadata && typeof node.metadata === 'object' ? node.metadata : {}) as Record<string, unknown>;
53	
54	  const rawLessons = md.lessons;
55	  if (Array.isArray(rawLessons) && rawLessons.length > 0) {
56	    const lessons = rawLessons
57	      .map((l, i) => normalizeLesson(l, node, i))
58	      .filter((l): l is ICanonicalNodeLesson => l !== null);
59	    if (lessons.length > 0) return lessons.sort((a, b) => a.order - b.order);
60	  }
61	
62	  const single = md.lesson;
63	  if (single && typeof single === 'object' && !Array.isArray(single)) {
64	    const L = single as Record<string, unknown>;
65	    return [
66	      {
67	        lessonId: typeof L.lessonId === 'string' && L.lessonId.trim() ? L.lessonId.trim() : node.nodeId,
68	        title: node.title,
69	        order: 0,
70	        content: typeof L.content === 'string' ? L.content : node.description?.trim() ?? '',
71	        contentFormat: L.contentFormat === 'html' ? 'html' : 'markdown',
72	        ...(typeof L.summary === 'string' ? { summary: L.summary } : {}),
73	        video: parseVideo(L.video)
74	      }
75	    ];
76	  }
77	
78	  return [
79	    {
80	      lessonId: node.nodeId,
81	      title: node.title,
82	      order: 0,
83	      content: node.description?.trim() ?? '',
84	      contentFormat: 'markdown',
85	      video: null
86	    }
87	  ];
88	}
